import{_ as e,o as l,c as t,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F01: 營收因子與定價權分析 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6239_力成/20260617/F01_營收因子與定價權分析.md","filePath":"審計報告庫/財務審計/6239_力成/20260617/F01_營收因子與定價權分析.md"}'),r={name:"審計報告庫/財務審計/6239_力成/20260617/F01_營收因子與定價權分析.md"};function i(n,a,h,s,d,c){return l(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="f01-營收因子與定價權分析-財務審計專家報告" tabindex="-1">F01: 營收因子與定價權分析 - 財務審計專家報告 <a class="header-anchor" href="#f01-營收因子與定價權分析-財務審計專家報告" aria-label="Permalink to &quot;F01: 營收因子與定價權分析 - 財務審計專家報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>營收成長或衰退的實質因子分析：是由於「銷量增加 (Volume Up)」還是「單價調整 (Price Up)」？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：營收驅動屬量增主導（Volume Up），ASP雖調漲但漲幅不及成本漲幅，毛利率反降至17.0%，定價權屬被動轉嫁非品牌溢價。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至2026年5月最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>力成2022-2025年營收分別為854.7億→697.4億(-18.4%)→742.0億(+6.4%)→749.3億(+2.2%)，呈現2023年劇烈衰退後逐步回升的V型復甦。毛利率20.7%→17.9%→19.1%→17.0%，2025年毛利率大幅回落至17.0%，為四年低點。營業利益率14.8%→11.6%→12.8%→10.9%，同步受壓。從月營收追蹤，2025年逐月走高(4月5,454M→12月7,140M)，2026年1-5月進一步跳升至7.30B→6.70B→7.37B→7.58B→7.92B，最新4月/5月YoY分別達+38.9%/+38.5%，動能顯著轉強。但毛利率反向下滑，暗示營收擴張的「含金量不足」。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="驅動因子權重" tabindex="-1">驅動因子權重 <a class="header-anchor" href="#驅動因子權重" aria-label="Permalink to &quot;驅動因子權重&quot;">​</a></h3><p>力成的營收成長主要由Volume（封測出貨量）驅動，而非ASP提升。2024年營收+6.4%對應毛利率+1.2pp，屬景氣復甦的正常量價回升。但2025年營收+2.2%對應毛利率-2.1pp，顯示2025年的營收成長是由產能利用率提升帶動的出貨量增加（封裝產能約90%、測試約85%），但原物料成本（金線、封裝材料）上漲侵蝕了毛利空間。法說會揭露2026年Q1已調漲價格，部分Q1生效、大部分Q2生效，ASP確實有結構性上調，但係成本驅動而非品牌溢價。</p><h3 id="獲利品質連動" tabindex="-1">獲利品質連動 <a class="header-anchor" href="#獲利品質連動" aria-label="Permalink to &quot;獲利品質連動&quot;">​</a></h3><p>2025年營業收入749.3億（年增+2.2%）但營業毛利127.3億（年減-9.0%），呈現「增收不增利」的典型警訊。營業成本由593.2億升至622.0億(+4.9%)，增幅遠大於營收增幅，成本結構失控。營業費用4,597M與前年4,609M大致持平，費用管控得當，成本問題集中於COGS端（材料與折舊）。2025年業外收益僅6.6億（前年13.0億），稅後淨利歸屬母公司51.4億（前年67.9億），EPS 7.10元（前年9.09元），淨利衰退24.3%。</p><h3 id="未來路徑預測" tabindex="-1">未來路徑預測 <a class="header-anchor" href="#未來路徑預測" aria-label="Permalink to &quot;未來路徑預測&quot;">​</a></h3><p>2026年Q1營收213億(YoY+37.8%)，毛利率回升至19.4%（2025全年17.0%），已反映漲價效益。4-5月月營收分別達75.8億/79.2億，延續強勁動能。管理層預期Q2毛利率突破20%、全年逐季成長。但需關注：(1)漲價是否會導致客戶轉單；(2)400億資本支出擴張對折舊的攤提壓力—若2027年量產營收未對等成長，毛利率恐再受壓。</p><h2 id="💡-專家評析-多空雙向分析" tabindex="-1">💡 專家評析（多空雙向分析） <a class="header-anchor" href="#💡-專家評析-多空雙向分析" aria-label="Permalink to &quot;💡 專家評析（多空雙向分析）&quot;">​</a></h2><h3 id="🔴-空方觀點-利空風險" tabindex="-1">🔴 空方觀點（利空風險） <a class="header-anchor" href="#🔴-空方觀點-利空風險" aria-label="Permalink to &quot;🔴 空方觀點（利空風險）&quot;">​</a></h3><ol><li><strong>成本轉嫁能力虛弱</strong>：ASP微幅調漲但毛利率反降2.1pp至17%（四年低點），漲幅跟不上材料成本漲幅，定價權僅屬被動轉嫁，不具「領先調價+利潤擴張」的品牌溢價護城河。</li><li><strong>增收不增利的結構瓶頸</strong>：2025年營收+2.2%但稅後淨利-24.3%，EPS從9.09降至7.10元。若折舊攀升致毛利率再度下滑，營收成長將持續無法轉化為回報。</li><li><strong>資本支出過度擴張</strong>：CapEx 400億使折舊在2027年顯著攀升，新製程良率爬坡壓縮毛利，且擴產全壓台灣未分散地緣風險。</li></ol><h3 id="🟢-多方觀點-機會可能性" tabindex="-1">🟢 多方觀點（機會可能性） <a class="header-anchor" href="#🟢-多方觀點-機會可能性" aria-label="Permalink to &quot;🟢 多方觀點（機會可能性）&quot;">​</a></h3><ol><li><strong>AI/HPC驅動結構性擴張</strong>：FOPLP良率達95%，2026下半年客戶認證、2027年中量產；光引擎年底量產、CPO預計2027-2028量產，先進封裝布局完整。</li><li><strong>漲價效益逐步兌現</strong>：2026Q1毛利率回升至19.4%，Q2指引突破20%。若ASP提升持續大於成本增幅，全年毛利率可回20%以上，EPS重返雙位數可期。</li><li><strong>產能滿載提供議價空間</strong>：封裝產能90%、測試85%、子公司滿載，產能稀缺創造漲價空間。退出低毛利Power Module有利產品組合優化。</li></ol><h3 id="⚖️-綜合權衡" tabindex="-1">⚖️ 綜合權衡 <a class="header-anchor" href="#⚖️-綜合權衡" aria-label="Permalink to &quot;⚖️ 綜合權衡&quot;">​</a></h3><p>營運動能強勁（月營收YoY+38%）但2025年增收不增利反映定價權有限。短期看產能利用率與漲價能否持續，中長期看FOPLP/HBM在2027年接棒成長。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (revenue_bridge margin_analysis 6239)</li><li>原始數據：FinMind TaiwanStockMonthRevenue、TaiwanStockFinancialStatements</li><li>查詢參數：stock_id=6239, start=2022-01-01, end=2025-12-31</li><li>年報數據：2025_Q4_6239_合併.pdf (pages 8-10，損益表)</li><li>法說會資訊：富果法說會備忘錄 20260428</li><li>網路搜尋：力成法說會展望 2025-2026</li><li>數據查詢日期：2026-06-17</li></ul>',23)])])}const p=e(r,[["render",i]]);export{u as __pageData,p as default};
